// === USER PROFILE / CV ===
// Edit USER_CV below with your real CV text. The AI agent uses it to
// match skills, score relevance, and identify gaps. Keep it concise (<2000 chars).
const USER_CV = `
Name: Your Name
Target Roles: Project Manager, Product Manager, Scrum Master, AI Project Manager, Program Manager, Technical Program Manager, Agile Project Manager
Experience: 0-3 years (entry to mid level)
Skills: Agile, Scrum, Jira, Confluence, Trello, Asana, Notion, stakeholder communication, sprint planning, roadmaps, requirements gathering, coordination, scheduling, delivery management, product thinking, basic SQL, Google Workspace, MS Office, AI tools (ChatGPT, n8n, Zapier).
Domains: SaaS, AI, automation, fintech (open).
Certifications (optional): CSM in progress, Google PM Certificate.
Preferences: Remote only, entry-to-mid level, no senior/executive roles.
Location: Remote / Worldwide.
`.trim();

return [{ json: { user_profile: USER_CV } }];

// === COLLECT RAW JOBS ===
// Handles both Webhook input and Schedule-trigger input.
// Webhook body can be: { jobs: [...] } or a plain array
// Schedule trigger: calls local backend for queued/raw jobs

const payload = items[0]?.json || {};
let rawJobs = [];

if (Array.isArray(payload)) {
  rawJobs = payload;
} else if (Array.isArray(payload.jobs)) {
  rawJobs = payload.jobs;
} else if (Array.isArray(payload.body?.jobs)) {
  rawJobs = payload.body.jobs;
} else if (Array.isArray(payload.body)) {
  rawJobs = payload.body;
}

// Keep only LinkedIn / Indeed sourced jobs (hard rule)
const allowed = ['linkedin', 'indeed'];
const filtered = rawJobs.filter(j => {
  const src = (j.source || '').toLowerCase();
  return allowed.some(a => src.includes(a));
});

return filtered.map(j => ({ json: j }));

// === PRE-FILTER: keep only remote PM/Product/Scrum/Management roles ===
const titleRe = /(project\s*manager|product\s*manager|program\s*manager|technical\s*program\s*manager|scrum\s*master|agile\s*(project\s*)?manager|associate\s*pm|junior\s*pm|apm|product\s*owner|ai\s*project\s*manager|delivery\s*manager|operations\s*manager|management|coordinator|team\s*lead)/i;
const seniorRe = /(senior|sr\.|staff|principal|director|head\s+of|vp|chief|manager\s+of\s+managers)/i;
const remoteRe = /(remote|worldwide|anywhere|distributed|work.from.home|wfh)/i;

const kept = [];
for (const item of items) {
  const j = item.json;
  const title = (j.title || '').toString();
  const loc = (j.location || '').toString();
  const remoteFlag = (j.remote_flag || '').toString();
  if (!titleRe.test(title)) continue;
  if (seniorRe.test(title)) continue;
  if (!remoteRe.test(loc) && !remoteRe.test(title) && !remoteRe.test(remoteFlag)) continue;
  // Must have an apply_link
  if (!j.apply_link && !j.source_url) continue;
  kept.push({ json: j });
}
return kept.length ? kept : [{ json: { _empty: true } }];

// === BATCH: combine user profile + filtered jobs into ONE item for AI ===
let userProfile = '';
try { userProfile = $items('User Profile (edit me)')[0].json.user_profile || ''; } catch(e) {}

const jobs = items.filter(i => !i.json._empty).map(i => {
  const j = i.json;
  return {
    title: j.title || '',
    company: j.company || '',
    location: j.location || '',
    description: (j.description || '').slice(0, 1000),
    source: j.source || '',
    source_url: j.source_url || '',
    apply_link: j.apply_link || '',
    posted_at: j.posted_at || '',
    seniority: j.seniority || '',
    tags: j.tags || [],
    salary: j.salary || '',
    remote_flag: j.remote_flag || ''
  };
});

if (jobs.length === 0) {
  return [{ json: { _no_jobs: true } }];
}

return [{ json: { user_profile: userProfile, raw_jobs: jobs, raw_count: jobs.length } }];

