// === PARSE AI OUTPUT ===
// Extracts: dashboard_jobs + email_jobs from AI response.
const raw = items[0]?.json;

let parsed = null;
const content = raw?.message?.content ?? raw?.choices?.[0]?.message?.content ?? raw?.content ?? raw;

try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  const m = String(content).match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (_) {} }
}

if (!parsed || !parsed.dashboard_jobs) {
  // Fallback: check if it's an array
  let arr = null;
  try { arr = typeof content === 'string' ? JSON.parse(content) : content; } catch(_) {}
  if (Array.isArray(arr)) {
    parsed = { dashboard_jobs: arr, email_jobs: arr.slice(0, 5).map(j => ({ title: j.title, company: j.company, score: j.score, apply_link: j.apply_link })) };
  } else {
    parsed = { dashboard_jobs: [], email_jobs: [] };
  }
}

return [{ json: parsed }];

// === EXTRACT dashboard_jobs into individual items for DB/Sheets ===
const parsed = items[0]?.json || {};
const rows = parsed.dashboard_jobs || [];
const today = new Date().toISOString().slice(0, 10);

if (rows.length === 0) {
  return [{ json: { _empty: true, Date: today, Title: 'No jobs found', Company: '', Location: '', Score: 0, Link: '', Status: 'New', Source: '', Summary: 'No matching jobs in this batch', Reason: '', SkillsMatch: '', SkillsMissing: '' } }];
}

return rows.map(j => ({
  json: {
    Date: today,
    JobId: j.job_id || '',
    Title: j.title || '',
    Company: j.company || '',
    Location: j.location || '',
    PostedAt: j.posted_at || '',
    Score: j.score ?? 0,
    Link: j.apply_link || '',
    Status: j.status || 'New',
    Source: j.source || '',
    Summary: j.summary || '',
    Reason: j.reason || '',
    SkillsMatch: Array.isArray(j.skills_match) ? j.skills_match.join(', ') : (j.skills_match || ''),
    SkillsMissing: Array.isArray(j.skills_missing) ? j.skills_missing.join(', ') : (j.skills_missing || '')
  }
}));

// === BUILD EMAIL from AI email_jobs array ===
const parsed = $items('Parse AI Response')[0]?.json || {};
const emailJobs = parsed.email_jobs || [];
const dashboardJobs = parsed.dashboard_jobs || [];

const subject = 'Daily Remote PM / Product Jobs';
const count = dashboardJobs.length;

const html = `
<h2>Daily Remote PM / Product Jobs</h2>
<p>Found <b>${count}</b> matching jobs today. Here are your top picks:</p>
<ol>
${emailJobs.map(r => `<li><b>${r.title}</b> — ${r.company} &nbsp; ⭐ ${r.score}/10<br><a href="${r.apply_link}">Apply →</a></li>`).join('\n')}
</ol>
<p><i>Check your dashboard for all ${count} jobs. Apply to your top picks today!</i></p>
`;

const text = [
  subject,
  '',
  `Found ${count} matching jobs today. Top picks:`,
  '',
  ...emailJobs.map((r, i) => `${i+1}. [${r.score}/10] ${r.title} — ${r.company}\n   ${r.apply_link}`),
  '',
  `Check your dashboard for all ${count} jobs.`
].join('\n');

return [{ json: { subject, html, text } }];
